webhooks.responseCode:
={{((parameters) => {
    if (parameters.responseCode) {
        return parameters.responseCode;
    }
    const responseCodeOptions = parameters.options;
    if (responseCodeOptions?.responseCode?.values) {
        const { responseCode, customCode } = responseCodeOptions.responseCode.values;
        if (customCode) {
            return customCode;
        }
        return responseCode;
    }
    return 200;
})($parameter)}}

input.code:
import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const waitNode = node({
  type: 'n8n-nodes-base.wait',
  version: 1.1,
  config: {
    name: 'Wait',
    parameters: {
      resume: 'timeInterval',
      amount: 1,
      unit: 'seconds'
    }
  }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'running state test',
    parameters: {}
  }
});

export default workflow('running-state-test', 'Manual Trigger - Wait - Set')
  .add(manualTrigger)
  .to(waitNode)
  .to(setNode);
